import { useState, useCallback } from 'react';

export interface TooltipState {
    visible: boolean;
    x: number;
    y: number;
    content: React.ReactNode;
    placement: 'left' | 'right';
}

export function useTooltip() {
    const [tooltip, setTooltip] = useState<TooltipState | null>(null);

    const showTooltip = useCallback((e: React.MouseEvent, content: React.ReactNode) => {
        const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
        const windowWidth = window.innerWidth;
        const windowHeight = window.innerHeight;

        // 预估浮窗宽度为 300px
        const estimatedWidth = 300;
        // 检查右侧空间是否足够
        const canPlaceRight = rect.right + estimatedWidth < windowWidth;
        const placement = canPlaceRight ? 'right' : 'left';

        // 计算 X 坐标：如果是右侧，则从 rect.right 开始；如果是左侧，则从 rect.left 开始
        const x = placement === 'right' ? rect.right + 12 : rect.left - 12;

        // Y 坐标尽量对齐顶部，但防止超出屏幕底部
        // 简单处理：直接对齐 rect.top
        const y = rect.top;

        setTooltip({
            visible: true,
            x,
            y,
            content,
            placement
        });
    }, []);

    const hideTooltip = useCallback(() => {
        setTooltip(prev => prev ? { ...prev, visible: false } : null);
    }, []);

    return { tooltip, showTooltip, hideTooltip };
